include("shared.lua")function ENT:Draw()	render.SuppressEngineLighting(true)	self:DrawModel()	render.SuppressEngineLighting(false)endlocal ring = Material("sgm/playercircle")function ENT:DrawTranslucent()	local trace = {}	trace.start = self:GetPos()	trace.endpos = trace.start + Vector(0, 0, -100)	trace.filter = self	trace.mask = MASK_SOLID_BRUSHONLY	local tr = util.TraceLine(trace)	if tr.HitPos then		render.SetMaterial(ring)		render.DrawQuadEasy(tr.HitPos + tr.HitNormal, tr.HitNormal, 20, 20, color_white)	endend